                        <Link
                          href={getPostUrl(post)}
                          className={`group flex items-start gap-3 py-2 px-2 -mx-2 rounded-lg no-underline transition-all duration-200 ${
                            isCurrent ? 'bg-accent/5' : 'hover:bg-muted/5'
                          }`}
